import React, { useEffect, useState } from 'react';
import axios from 'axios';

function Cadastro() {
  const [clinics, setClinics] = useState([]);
  const [form, setForm] = useState({
    clinic_id: '',
    patient_name: '',
    patient_phone: '',
    channel: '',
    description: '',
    service_type: '',
    file: null
  });

  // 🔹 carregar clínicas
  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => setClinics(res.data))
      .catch(err => console.error(err));
  }, []);

  // 🔹 envio
  const handleSubmit = async () => {
    try {
      const formData = new FormData();

      formData.append('clinic_id', form.clinic_id);
      formData.append('patient_name', form.patient_name);
      formData.append('patient_phone', form.patient_phone);
      formData.append('channel', form.channel);
      formData.append('description', form.description);
      formData.append('service_type', form.service_type);

      if (form.file) {
        formData.append('file', form.file);
      }

      await axios.post('http://localhost:3001/complaints', formData);

      alert('Reclamação salva com sucesso!');

    } catch (error) {
      console.error(error);
      alert('Erro ao salvar');
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: 'auto', padding: 20 }}>
      <h2>Cadastro de Reclamação</h2>

      {/* CLÍNICA */}
      <select onChange={(e) => setForm({ ...form, clinic_id: e.target.value })}>
        <option>Selecione a clínica</option>
        {clinics.map(c => (
          <option key={c.id} value={c.id}>
            {c.name}
          </option>
        ))}
      </select>

      <br /><br />

      {/* PACIENTE */}
      <input
        placeholder="Nome do paciente"
        onChange={(e) => setForm({ ...form, patient_name: e.target.value })}
      />

      <br /><br />

      {/* TELEFONE */}
      <input
        placeholder="Telefone"
        onChange={(e) => setForm({ ...form, patient_phone: e.target.value })}
      />

      <br /><br />

      {/* CANAL */}
      <select onChange={(e) => setForm({ ...form, channel: e.target.value })}>
        <option>Canal</option>
        <option value="whatsapp">WhatsApp</option>
        <option value="email">Email</option>
        <option value="google">Google</option>
        <option value="facebook">Facebook</option>
        <option value="instagram">Instagram</option>
        <option value="nps">NPS</option>
      </select>

      <br /><br />

      {/* SERVIÇO */}
      <select onChange={(e) => setForm({ ...form, service_type: e.target.value })}>
        <option>Tipo de serviço</option>
        <option value="clinico">Clínico Geral</option>
        <option value="ortodontia">Ortodontia</option>
        <option value="implante">Implante</option>
        <option value="endodontia">Endodontia</option>
      </select>

      <br /><br />

      {/* DESCRIÇÃO */}
      <textarea
        placeholder="Descrição da reclamação"
        onChange={(e) => setForm({ ...form, description: e.target.value })}
      />

      <br /><br />

      {/* UPLOAD */}
      <input
        type="file"
        onChange={(e) => setForm({ ...form, file: e.target.files[0] })}
      />

      <br /><br />

      <button onClick={handleSubmit}>
        Salvar Reclamação
      </button>
    </div>
  );
}

export default Cadastro;
